#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char line[64];
    getchar(); // consume newline after T
    const char *mp[9][2] = {
        {"MagicalCreature", "[]"},
        {"Dragon", "['fly']"},
        {"FireDragon", "['breathe fire']"},
        {"WaterDragon", "['swim']"},
        {"EarthDragon", "['dig']"},
        {"FireWaterDragon", "['fly', 'breathe fire', 'swim']"},
        {"FireEarthDragon", "['fly', 'breathe fire', 'dig']"},
        {"WaterEarthDragon", "['fly', 'swim', 'dig']"},
        {"UltimateDragon", "['fly', 'breathe fire', 'swim', 'dig']"}
    };
    while (T--) {
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        const char *out = "[]";
        for (int i = 0; i < 9; ++i) {
            if (strcmp(line, mp[i][0]) == 0) { out = mp[i][1]; break; }
        }
        printf("%s\n", out);
    }
    return 0;
}

