import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        Map<String, String> mp = new HashMap<>();
        mp.put("MagicalCreature", "[]");
        mp.put("Dragon", "['fly']");
        mp.put("FireDragon", "['breathe fire']");
        mp.put("WaterDragon", "['swim']");
        mp.put("EarthDragon", "['dig']");
        mp.put("FireWaterDragon", "['fly', 'breathe fire', 'swim']");
        mp.put("FireEarthDragon", "['fly', 'breathe fire', 'dig']");
        mp.put("WaterEarthDragon", "['fly', 'swim', 'dig']");
        mp.put("UltimateDragon", "['fly', 'breathe fire', 'swim', 'dig']");
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            String name = br.readLine();
            if (name == null) name = "";
            String out = mp.getOrDefault(name.trim(), "[]");
            sb.append(out);
            if (i + 1 < T) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

